solutions.python:
class Solution:
  def is_valid_commit_message(self, message: str) -> bool:
    if len(message) > 50:
      return False
    return True

# Test the solution
if __name__ == '__main__':
  solution = Solution()
  print(solution.is_valid_commit_message('feat: Fixed bug 123'))  # Should print: True
  print(solution.is_valid_commit_message('fix: This is a very long commit message that exceeds 50 characters and is not a valid commit message'))  # Should print: False
